// ============================================
// CONFIGURACION: Empresas a investigar
// ============================================
// Agrega slugs de empresas que existan en Empliq.
// Usa api.empliq.io/api/companies?search=nombre para buscar slugs.
//
// Para ejecutar por lotes, cambia este array.

const companySlugs = [
  'banco-de-credito-del-peru',
  'interbank',
  'bbva-peru',
  'scotiabank-peru',
  'rimac-seguros',
  'telefonica-del-peru',
  'alicorp',
  'backus',
  'southern-peru',
  'minsur'
];

return companySlugs.map(slug => ({ json: { companySlug: slug } }));

// Parse AI Agent output into structured salary data
const agentOutput = $input.first().json.output || $input.first().json.text || '';

try {
  // Extract JSON from the response (handle markdown code blocks)
  let jsonStr = agentOutput;

  // Remove markdown code fences if present
  const jsonMatch = jsonStr.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (jsonMatch) {
    jsonStr = jsonMatch[1].trim();
  }

  // Try to find JSON array in the response
  const arrayMatch = jsonStr.match(/\[\s*\{[\s\S]*\}\s*\]/);
  if (arrayMatch) {
    jsonStr = arrayMatch[0];
  }

  const salaries = JSON.parse(jsonStr);

  if (!Array.isArray(salaries) || salaries.length === 0) {
    console.log('No salaries found in AI response');
    return { json: { salaries: [], count: 0, skipped: true } };
  }

  // Validate and clean each salary
  const validSalaries = salaries
    .filter(s => s.companySlug && s.positionTitle && s.amount > 0)
    .map(s => ({
      companySlug: String(s.companySlug).trim(),
      positionTitle: String(s.positionTitle).trim(),
      level: s.level || undefined,
      amount: Math.round(Number(s.amount)),
      currency: s.currency || 'PEN',
      period: s.period || 'monthly',
      yearsExperience: s.yearsExperience ? Number(s.yearsExperience) : undefined,
      source: s.source || 'ai-agent'
    }));

  console.log(`Parsed ${validSalaries.length} valid salaries from AI response`);

  return { json: { salaries: validSalaries, count: validSalaries.length } };

} catch (err) {
  console.error('Failed to parse AI response:', err.message);
  console.log('Raw output:', agentOutput.substring(0, 500));
  return { json: { salaries: [], count: 0, error: err.message } };
}

const result = $input.first().json;

const created = result.created || 0;
const errors = result.errors ? result.errors.length : 0;
const total = result.total || 0;

console.log(`✅ Salary Seed Complete`);
console.log(`   Total: ${total} | Created: ${created} | Errors: ${errors}`);

if (result.errors && result.errors.length > 0) {
  console.log('Errors:');
  result.errors.forEach(e => console.log(`   [${e.index}] ${e.companySlug}/${e.positionTitle}: ${e.error}`));
}

return { json: { summary: `Seeded ${created}/${total} salaries (${errors} errors)`, ...result } };
